  1	import * as React from 'react';
  2	import {
  3	  MenuToggle,
  4	  MenuToggleElement,
  5	  Select,
  6	  SelectList,
  7	  SelectOption,
  8	  Tooltip,
  9	  TooltipPosition
 10	} from '@patternfly/react-core';
 11	import { kialiStyle } from 'styles/StyleUtils';
 12	import { classes } from 'typestyle';
 13	
 14	const dropdownTitle = kialiStyle({
 15	  alignSelf: 'center',
 16	  marginRight: '10px'
 17	});
 18	
 19	type ToolbarDropdownProps = {
 20	  className?: string;
 21	  disabled?: boolean;
 22	  handleSelect: (value: string) => void;
 23	  id: string;
 24	  label: string;
 25	  nameDropdown?: string;
 26	  nameDropdownClassName?: string;
 27	  onToggle?: (isOpen: boolean) => void;
 28	  options: { [k: string]: string } | string[];
 29	  tooltip?: string;
 30	  tooltipPosition?: TooltipPosition;
 31	  value?: number | string;
 32	};
 33	
 34	export const ToolbarDropdown: React.FC<ToolbarDropdownProps> = (props: ToolbarDropdownProps) => {
 35	  const [isOpen, setIsOpen] = React.useState<boolean>(false);
 36	
 37	  const onKeyChanged = (_event?: React.MouseEvent<Element, MouseEvent>, selection?: string | number): void => {
 38	    if (selection) {
 39	      props.handleSelect(String(selection));
 40	    }
 41	
 42	    setIsOpen(false);
 43	  };
 44	
 45	  const onToggleClick = (): void => {
 46	    setIsOpen(!isOpen);
 47	    props.onToggle && props.onToggle(isOpen);
 48	  };
 49	
 50	  const toggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
 51	    <MenuToggle
 52	      id={`${props.id}-toggle`}
 53	      ref={toggleRef}
 54	      onClick={onToggleClick}
 55	      isExpanded={isOpen}
 56	      isDisabled={props.disabled}
 57	      className={props.className}
 58	    >
 59	      {props.label}
 60	    </MenuToggle>
 61	  );
 62	
 63	  const dropdownButton = (
 64	    <Select
 65	      toggle={toggle}
 66	      onSelect={onKeyChanged}
 67	      aria-label={props.id}
 68	      selected={props.value}
 69	      id={props.id}
 70	      data-test={props.id}
 71	      onOpenChange={isOpen => setIsOpen(isOpen)}
 72	      isOpen={isOpen}
 73	      aria-labelledby={props.id}
 74	    >
 75	      <SelectList>
 76	        {Object.keys(props.options).map(key => {
 77	          return (
 78	            <SelectOption
 79	              id={key}
 80	              key={key}
 81	              isDisabled={props.disabled}
 82	              isSelected={key === String(props.value)}
 83	              value={`${key}`}
 84	            >
 85	              {props.options[key]}
 86	            </SelectOption>
 87	          );
 88	        })}
 89	      </SelectList>
 90	    </Select>
 91	  );
 92	
 93	  return (
 94	    <>
 95	      {props.nameDropdown && (
 96	        <span id={`${props.id}-name`} className={classes(dropdownTitle, props.nameDropdownClassName)}>
 97	          {props.nameDropdown}
 98	        </span>
 99	      )}
100	      {props.tooltip ? (
101	        <Tooltip
102	          key={`ot-${props.id}`}
103	          entryDelay={1000}
104	          position={props.tooltipPosition ? props.tooltipPosition : TooltipPosition.auto}
105	          content={<>{props.tooltip}</>}
106	        >
107	          {dropdownButton}
108	        </Tooltip>
109	      ) : (
110	        dropdownButton
111	      )}
112	    </>
113	  );
114	};

