13	    options: serverConfig.durations
14	  },
15	  {
16	    id: 'metrics_filter_poll_interval',
17	    default: config.toolbar.defaultRefreshInterval,
18	    options: config.toolbar.refreshInterval
19	  },
20	  { id: 'graph_filter_layouts', default: 'cola', options: config.toolbar.graphLayouts }
21	];
22	
23	describe('ToolbarDropdown', () => {
24	  it('Render correctly the toolbar dropdown', () => {
25	    data.forEach(dropdownType => {
26	      const wrapper = shallow(
27	        <ToolbarDropdown
28	          id={dropdownType.id}
29	          disabled={false}
30	          handleSelect={jest.fn()}
31	          nameDropdown={dropdownType.id}
32	          value={dropdownType.default}
33	          label={dropdownType.options[dropdownType.default]}
34	          options={dropdownType.options}
35	        />
36	      );
37	      expect(shallowToJson(wrapper)).toMatchSnapshot();
38	    });
39	  });
40	});

